setup:
import { registerStyle, setStyle, setMode } from 'decantr/css';
import { clay } from 'decantr/styles/community/clay';
registerStyle(clay);
setStyle('clay');
setMode('light');

panel.example:
const { div, span } = tags;
div({ class: css('cy-pillow _p4 _r4') },
  div({ class: css('_flex _aic _jcsb _mb3') },
    span({ class: css('cy-label') }, 'SECTION'),
  ),
  div({ class: css('_flex _col _gap3') },
    // content here
  )
)

card.example:
Card({ hover: true, class: css('cy-pillow cy-jelly cy-squish') },
  Card.Body({},
    span({ class: css('_heading4') }, 'Card Title'),
    p({ class: css('_textsm _fgmuted') }, 'Card content')
  )
)

kpi.example:
Statistic({
  label: 'Total Items',
  value: 1200,
  trend: 'up',
  trendValue: '+8%',
  animate: 1200,
  class: css('cy-pillow')
})

